phase3.solution:
abstract class Appliance {
    String brand;

    Appliance(String brand) {
        this.brand = brand;
    }

    void turnOn() {
        System.out.println(brand + " is turning on");
    }

    abstract void operate();
}

class WashingMachine extends Appliance {
    WashingMachine(String brand) {
        super(brand);
    }

    @Override
    void operate() {
        System.out.println(brand + " is washing clothes");
    }
}

class Microwave extends Appliance {
    Microwave(String brand) {
        super(brand);
    }

    @Override
    void operate() {
        System.out.println(brand + " is heating food");
    }
}

public class Main {
    public static void main(String[] args) {
        Appliance[] appliances = {
            new WashingMachine("Samsung"),
            new Microwave("Panasonic")
        };

        for (Appliance a : appliances) {
            a.turnOn();
            a.operate();
            System.out.println("---");
        }
    }
}
